import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework._O8Cueap.js";const g=JSON.parse('{"title":"Conversations","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/conversations.md","filePath":"concepts/conversations.md"}'),n={name:"concepts/conversations.md"};function i(r,e,l,c,d,h){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="conversations" tabindex="-1">Conversations <a class="header-anchor" href="#conversations" aria-label="Permalink to &quot;Conversations&quot;">​</a></h1><p>Conversations let users chat directly with an agent outside the workflow engine.</p><h2 id="what-a-conversation-is" tabindex="-1">What a Conversation Is <a class="header-anchor" href="#what-a-conversation-is" aria-label="Permalink to &quot;What a Conversation Is&quot;">​</a></h2><ul><li>A conversation is a persisted thread between one user and one selected agent.</li><li>Each conversation belongs to a workspace and is recorded in the database.</li><li>The conversation history is stored as ordered <code>user</code> and <code>assistant</code> messages, so users can leave and resume later.</li><li>The selected agent can be switched later from the conversation screen, so subsequent turns can continue with a different active agent while keeping the same transcript.</li></ul><h2 id="starting-a-conversation" tabindex="-1">Starting a Conversation <a class="header-anchor" href="#starting-a-conversation" aria-label="Permalink to &quot;Starting a Conversation&quot;">​</a></h2><ul><li>Open <strong>Conversations</strong> from the workspace navigation and create a new thread.</li><li>Choose one active agent from the available agent list.</li><li>Optionally provide a title; otherwise OAO generates one automatically.</li><li>Agent detail pages include a <strong>Start Conversation</strong> shortcut that preselects that agent.</li></ul><h2 id="interactive-behavior" tabindex="-1">Interactive Behavior <a class="header-anchor" href="#interactive-behavior" aria-label="Permalink to &quot;Interactive Behavior&quot;">​</a></h2><ul><li>Messages are stored immediately when the user sends them.</li><li>The assistant response is created as a pending message and then streamed into the UI as deltas arrive.</li><li>Conversation pages subscribe to server-sent events (SSE), so the transcript updates while the agent is still responding.</li><li>The stream can include visible reasoning blocks, reasoning deltas, turn lifecycle markers, and tool execution events so the UI can show what the agent is doing while a turn is running.</li><li>Only one assistant turn can run at a time for a conversation.</li></ul><h2 id="conversation-controls" tabindex="-1">Conversation Controls <a class="header-anchor" href="#conversation-controls" aria-label="Permalink to &quot;Conversation Controls&quot;">​</a></h2><ul><li>The conversation page can override the next turn&#39;s model selection using the active records from the workspace <strong>Models</strong> registry.</li><li>The conversation page can override the next turn&#39;s reasoning effort (<code>low</code>, <code>medium</code>, <code>high</code>, <code>xhigh</code>) when the chosen model supports it.</li><li>The conversation page can override the agent&#39;s tool defaults by selecting or clearing both built-in tools and discovered MCP tools for the next turn.</li><li>These per-turn settings are stored in conversation message metadata so the UI can restore the last-used settings for the thread.</li></ul><p>The turn controls live in a compact bar directly below the prompt input, similar to editor-integrated chat tools. Agent, model, and reasoning selectors stay inline, while tools open in a popup tree so the transcript keeps most of the available screen space.</p><p>The tool selector uses the same grouped catalog model as the agent editor:</p><ul><li>Built-in tools are grouped by capability area.</li><li>The default OAO Platform MCP server is auto-included.</li><li>Stored MCP servers and template-defined MCP servers appear as separate groups.</li><li>Resetting the selector returns the conversation to the current agent defaults.</li></ul><h2 id="agent-context" tabindex="-1">Agent Context <a class="header-anchor" href="#agent-context" aria-label="Permalink to &quot;Agent Context&quot;">​</a></h2><ul><li>Conversations use the selected agent&#39;s markdown instructions, skills, built-in tools, MCP servers, and scoped variables.</li><li>Workflow-specific tools such as workflow editing and self-scheduling are intentionally excluded from conversation sessions because there is no workflow execution context.</li><li>The same per-agent session lock used by workflow steps also applies to conversations, so an agent cannot run conflicting Copilot sessions at the same time.</li></ul><h2 id="persistence-model" tabindex="-1">Persistence Model <a class="header-anchor" href="#persistence-model" aria-label="Permalink to &quot;Persistence Model&quot;">​</a></h2><ul><li><code>conversations</code> stores the thread header, selected agent, and timestamps.</li><li><code>conversation_messages</code> stores each turn, its status, any assistant error, and assistant metadata such as agent/model selection, reasoning text, live tool activity, and tool trace.</li><li>If an agent is deleted later, the existing conversation remains readable, but new turns are disabled.</li></ul><h2 id="typical-use-cases" tabindex="-1">Typical Use Cases <a class="header-anchor" href="#typical-use-cases" aria-label="Permalink to &quot;Typical Use Cases&quot;">​</a></h2><ul><li>Ask an agent ad hoc questions before formalizing the task into a workflow.</li><li>Validate an agent&#39;s prompt design interactively from its detail page.</li><li>Keep a lightweight working thread with an agent while still using workflows for repeatable automation.</li></ul>',19)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
